const fileName = "20260409-Chargerent-1.1.1.0-OU-FOTA.pac";
const fileSize = 374957;
const filePath = "/home/george/.node-red/public/firmware/" + fileName;
const req = msg.req || {};
const res = msg.res && (msg.res._res || msg.res);
const headers = req.headers || {};
const remoteAddress = req.ip || req.connection?.remoteAddress || req.socket?.remoteAddress || "unknown";
const userAgent = headers['user-agent'] || headers['User-Agent'] || '';
const range = headers.range || "full";
const routeRequestId = req.params?.requestId || '';
const requestId = String(routeRequestId || global.get('activeFirmwareUpdateSession')?.requestId || '').trim();

function parseRangeHeader(rangeHeader) {
    const match = String(rangeHeader || '').match(/^bytes=(\d*)-(\d*)$/i);
    if (!match) {
        return { start: 0, end: fileSize - 1, full: true };
    }

    const start = match[1] === '' ? 0 : Number(match[1]);
    const end = match[2] === '' ? fileSize - 1 : Number(match[2]);
    return {
        start: Number.isFinite(start) ? Math.max(0, start) : 0,
        end: Number.isFinite(end) ? Math.min(fileSize - 1, end) : fileSize - 1,
        full: false
    };
}

function buildStatusMessage(status, statusLabel, extra = {}) {
    if (!requestId) return null;
    const now = Date.now();
    const session = global.get('firmwareUpdateSessionByRequestId:' + requestId) || global.get('activeFirmwareUpdateSession') || {};
    const content = {
        ...session,
        active: true,
        requestId,
        stationid: session.stationid || session.stationId || '',
        stationId: session.stationid || session.stationId || '',
        moduleid: session.moduleid || session.moduleId || '',
        moduleId: session.moduleid || session.moduleId || '',
        target: session.target || 'mcu',
        fileName,
        size: fileSize,
        status,
        phase: status,
        statusLabel,
        remoteAddress,
        userAgent,
        lastRange: range,
        updatedAtMillis: now,
        lastDownloadAt: new Date(now).toISOString(),
        ...extra
    };
    Object.keys(content).forEach((key) => {
        if (content[key] === undefined) {
            delete content[key];
        }
    });
    global.set('firmwareUpdateSessionByRequestId:' + requestId, content);
    global.set('activeFirmwareUpdateSession', content);
    if (content.stationid && content.moduleid) {
        global.set('firmwareUpdateSession:' + content.stationid + ':' + content.moduleid, content);
    }
    return {
        payload: {
            path: 'firmwareUpdateSessions/' + requestId,
            content
        }
    };
}

node.warn('Firmware stream requested by ' + remoteAddress + ' range=' + range + ' requestId=' + (requestId || 'n/a'));

if (!res || typeof res.sendFile !== "function") {
    node.error("HTTP response object does not expose res.sendFile(); cannot stream firmware", msg);
    msg.statusCode = 500;
    msg.headers = { "Content-Type": "text/plain; charset=utf-8" };
    msg.payload = "Firmware streaming is not available on this Node-RED response object";
    return msg;
}

const responseHeaders = {
    "Content-Type": "application/octet-stream",
    "Cache-Control": "no-store",
    "Accept-Ranges": "bytes",
    "X-Firmware-File": fileName,
    "X-Firmware-Request-Id": requestId || "manual"
};

res.sendFile(filePath, { headers: responseHeaders }, (error) => {
    const parsedRange = parseRangeHeader(range);
    const bytesDownloaded = Math.min(fileSize, parsedRange.end + 1);
    const percent = Math.max(0, Math.min(100, Math.round((bytesDownloaded / fileSize) * 100)));
    const complete = parsedRange.end >= fileSize - 1;

    if (error) {
        node.error('Firmware stream failed for ' + fileName + ': ' + error.message, msg);
        node.send(buildStatusMessage('failed_download', 'Firmware download failed at ' + percent + '%', {
            bytesDownloaded,
            percent,
            downloadComplete: false,
            error: error.message
        }));
        try {
            if (!res.headersSent) {
                res.status(error.statusCode || error.status || 500).send("Firmware download failed");
            }
        } catch (sendError) {
            node.error('Firmware stream error response failed: ' + sendError.message);
        }
        return;
    }

    const lastPercentKey = 'firmwareUpdateLastPercent:' + requestId;
    const previousPercent = Number(global.get(lastPercentKey));
    const shouldWriteStatus = requestId && (complete || previousPercent !== percent || percent === 0);
    global.set(lastPercentKey, percent);

    node.warn('Firmware stream completed for ' + remoteAddress + ' range=' + range + ' requestId=' + (requestId || 'n/a') + ' percent=' + percent);

    if (shouldWriteStatus) {
        node.send(buildStatusMessage(
            complete ? 'download_complete' : 'downloading',
            complete ? 'Firmware file downloaded by module' : 'Downloading firmware ' + percent + '%',
            {
                bytesDownloaded,
                percent,
                downloadComplete: complete,
                downloadCompletedAt: complete ? new Date().toISOString() : undefined
            }
        ));
    }
});

return null;
